import{_ as o,c as l,o as i,ag as r}from"./chunks/framework.DPDPlp3K.js";const h=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduce/introduce/faq.md","filePath":"guide/introduce/introduce/faq.md","lastUpdated":null}'),t={name:"guide/introduce/introduce/faq.md"};function a(s,e,n,d,u,c){return i(),l("div",null,e[0]||(e[0]=[r('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><blockquote><p>安装、录制、上传、WebUI、配置分类解答。如有其他问题欢迎到 <a href="https://github.com/biliup/biliup/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 反馈。</p></blockquote><hr><h2 id="安装相关" tabindex="-1">安装相关 <a class="header-anchor" href="#安装相关" aria-label="Permalink to &quot;安装相关&quot;">​</a></h2><p><strong>提示找不到 <code>biliup</code> 命令？</strong></p><ul><li>检查 uv 是否正确安装：<code>uv --version</code></li><li>检查 pip 是否正确安装：<code>pip3 --version</code></li><li>Docker 用户确认容器已启动：<code>docker ps -a</code></li></ul><p><strong>Windows 下 <code>.exe</code> 无法运行？</strong></p><ul><li>确认下载的是最新版 <code>biliup.exe</code></li><li>检查杀毒软件是否拦截</li></ul><hr><h2 id="录制相关" tabindex="-1">录制相关 <a class="header-anchor" href="#录制相关" aria-label="Permalink to &quot;录制相关&quot;">​</a></h2><p><strong>只能录制 5 个主播，第 6 个不工作？</strong></p><ul><li>默认下载线程池大小为 5。修改「空间配置」→「下载线程池大小 (pool1_size)」后<strong>重启</strong> biliup。</li></ul><p><strong>快手录制不稳定？</strong></p><ul><li>快手风控严格，目前没有完美的解决方案。</li></ul><p><strong>HLS 流不会录制（如 B站 APEX 分区）？</strong></p><ul><li>下载器改为 <code>streamlink</code>，安装 FFmpeg，配置 Cookie 和协议为 <code>hls_fmp4</code>。</li></ul><p><strong>境外服务器录制 B站？</strong></p><ul><li>需要自备国内机器反代 <code>https://api.live.bilibili.com</code>，将反代地址填入「各平台设置」→「哔哩哔哩」→「直播主 API」。</li></ul><hr><h2 id="上传相关" tabindex="-1">上传相关 <a class="header-anchor" href="#上传相关" aria-label="Permalink to &quot;上传相关&quot;">​</a></h2><p><strong>配置了自动上传但没有上传行为？</strong></p><ul><li>检查模板中「上传插件」是否为 <code>biliup-rs</code>（非默认的 <code>Noop</code>）。</li><li>检查文件名模板是否包含 <code>{streamer}</code>，缺少此标识符将无法识别。</li></ul><p><strong>上传日志出现 <code>Retry attempt</code>？</strong></p><ul><li>调整上传并发数，从 1 开始逐渐增加。</li></ul><p><strong>上传速度慢？</strong></p><ul><li>B站上传速度主要取决于上行带宽，国内用户使用境外服务器通常更快。</li></ul><p><strong>边录边传对机器要求高吗？</strong></p><ul><li>极低：1核 0.5G 内存即可同时录制 10 个直播间。但需要稳定上传带宽。</li></ul><hr><h2 id="画质相关" tabindex="-1">画质相关 <a class="header-anchor" href="#画质相关" aria-label="Permalink to &quot;画质相关&quot;">​</a></h2><p><strong>录制画质模糊/不高？</strong></p><ul><li>户外主播码率不稳定，属于源流问题。</li><li>部分平台（如抖音）需要 Cookie 才能拉取最高画质。</li><li>B站会对上传视频进行二压，原视频 10000 码率上传后可能只有 6000。</li></ul><hr><h2 id="webui-相关" tabindex="-1">WebUI 相关 <a class="header-anchor" href="#webui-相关" aria-label="Permalink to &quot;WebUI 相关&quot;">​</a></h2><p><strong>无法访问 WebUI？</strong></p><ul><li>确认端口 19159 未被防火墙/安全组拦截。</li><li>检查 <code>biliup server</code> 是否正确启动。</li><li>Docker 用户确认端口映射正确。</li></ul><p><strong>修改配置后不生效？</strong></p><ul><li>全局设置修改后必须<strong>重启</strong> biliup。</li></ul><p><strong>docker 容器数据丢失？</strong></p><ul><li>确保挂载了 <code>/opt</code> 目录：<code>-v /你的目录:/opt</code>。</li></ul><hr><h2 id="配置相关" tabindex="-1">配置相关 <a class="header-anchor" href="#配置相关" aria-label="Permalink to &quot;配置相关&quot;">​</a></h2><p><strong>如何启用自动投稿？</strong></p><ul><li>进入「空间配置」→ 在模板中将「上传插件」从 <code>Noop</code> 改为 <code>biliup-rs</code>。</li></ul><p><strong>如何添加多个 B站账号？</strong></p><ul><li>进入「投稿管理」→ 点击左上角图标 →「新增」→ 扫码登录。</li></ul><p><strong>如何修改录制保存路径？</strong></p><ul><li>修改 <code>biliup server</code> 的运行目录，或 Docker 用户修改 <code>-v</code> 挂载路径。</li></ul>',48)]))}const g=o(t,[["render",a]]);export{h as __pageData,g as default};
